def _iceberg_table_to_nested(iceberg_table: IcebergTable) -> IcebergTableNested:
    """Convert flat IcebergTable to nested format."""
    attrs = IcebergTableAttributes()
    _populate_iceberg_table_attrs(attrs, iceberg_table)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        iceberg_table, _ICEBERG_TABLE_REL_FIELDS, IcebergTableRelationshipAttributes
    )
    return IcebergTableNested(
        guid=iceberg_table.guid,
        type_name=iceberg_table.type_name,
        status=iceberg_table.status,
        version=iceberg_table.version,
        create_time=iceberg_table.create_time,
        update_time=iceberg_table.update_time,
        created_by=iceberg_table.created_by,
        updated_by=iceberg_table.updated_by,
        classifications=iceberg_table.classifications,
        classification_names=iceberg_table.classification_names,
        meanings=iceberg_table.meanings,
        labels=iceberg_table.labels,
        business_attributes=iceberg_table.business_attributes,
        custom_attributes=iceberg_table.custom_attributes,
        pending_tasks=iceberg_table.pending_tasks,
        proxy=iceberg_table.proxy,
        is_incomplete=iceberg_table.is_incomplete,
        provenance_type=iceberg_table.provenance_type,
        home_id=iceberg_table.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _iceberg_table_from_nested(nested: IcebergTableNested) -> IcebergTable:
    """Convert nested format to flat IcebergTable."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else IcebergTableAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _ICEBERG_TABLE_REL_FIELDS,
        IcebergTableRelationshipAttributes,
    )
    return IcebergTable(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_iceberg_table_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _iceberg_table_to_nested_bytes(iceberg_table: IcebergTable, serde: Serde) -> bytes:
    """Convert flat IcebergTable to nested JSON bytes."""
    return serde.encode(_iceberg_table_to_nested(iceberg_table))


def _iceberg_table_from_nested_bytes(data: bytes, serde: Serde) -> IcebergTable:
    """Convert nested JSON bytes to flat IcebergTable."""
    nested = serde.decode(data, IcebergTableNested)
    return _iceberg_table_from_nested(nested)


